**Example Code (iOS)**

Here's an example of how to implement background services for location updates in iOS:

```swift
// LocationService.swift (background service)
import CoreLocation

class LocationService: NSObject, CLLocationManagerDelegate {
    let locationManager = CLLocationManager()

    override init() {
        super.init()
        locationManager.delegate = self
        locationManager.requestAlwaysAuthorization()
    }

    func locationManager(_ manager: CLLocationManager, didUpdateLocations locations: [CLLocation]) {
        // Process location update
        print("Location updated: \(locations.last?.coordinate.latitude ?? 0), \(locations.last?.coordinate.longitude ?? 0)")
    }

    func locationManager(_ manager: CLLocationManager, didFailWithError error: Error) {
        // Handle location update failure
        print("Location update failed: \(error.localizedDescription)")
    }
}
```

```swift
// ViewController.swift (foreground view controller)
import UIKit
import CoreLocation

class ViewController: UIViewController {
    let locationManager = CLLocationManager()

    override func viewDidLoad() {
        super.viewDidLoad()
        locationManager.requestAlwaysAuthorization()
    }

    @IBAction func startServiceButtonTapped(_ sender: UIButton) {
        // Start location service
        locationManager.startUpdatingLocation()
    }

    @IBAction func stopServiceButtonTapped(_ sender: UIButton) {
        // Stop location service
        locationManager.stopUpdatingLocation()
    }
}
```

In both examples, the background service is responsible for requesting location updates and processing the updates received from the location manager. The foreground activity or view controller is responsible for starting and stopping the background service as needed.
